-- ملء محتوى عنقود "مقاصد الشريعة" (maqasid-sharia) — خمسة تصنيفات فرعية
-- draft بالكامل: المفهوم والتاريخ (mafhum-maqasid)، الكليات الخمس
-- (kulliyat-khams)، مراتب المصالح (maratib-masalih)، المآلات (maalat)،
-- التطبيقات وضوابط الاستدلال (tatbiqat-istidlal). كل تصنيف يحصل على
-- درس واحد (lessons + lesson_sections + lesson_citations)، بنفس أسلوب
-- الدفعات السابقة (body + examples).
-- المصادر المعتمدة: الشاطبي "الموافقات" (المصدر التأسيسي الكلاسيكي
-- للكليات الخمس ومراتب المصالح واعتبار المآل)، ابن عاشور "مقاصد
-- الشريعة الإسلامية" (تعريف العلم وتاريخ نشأته)، يوسف القرضاوي "دراسة
-- في فقه مقاصد الشريعة: بين المقاصد الكلية والنصوص الجزئية" (ضوابط
-- الاستدلال بالمقاصد).
-- ثلاث آيات تحقَّقت حرفياً محليًا من
-- artifacts/majalis/public/data/quran عبر numberInSurah: الأنبياء 107
-- (الرحمة المهداة)، الإسراء 33 (تحريم القتل)، البقرة 185 (رخصة
-- الفطر). أربعة أحاديث استُشهد بها، تحقَّقت عبر WebSearch قبل
-- الإدراج: «إن دماءكم وأموالكم وأعراضكم عليكم حرام كحرمة يومكم هذا»
-- عن أبي بكرة (متفق عليه، البخاري 67 ومسلم 1679)، «إن الدين يسر ولن
-- يشادّ الدين أحد إلا غلبه» عن أبي هريرة (البخاري 39)، «لولا حداثة
-- عهد قومك بالكفر لنقضت الكعبة ولجعلتها على أساس إبراهيم» عن عائشة
-- (متفق عليه، البخاري 1585 ومسلم 1333)، «لا يصلين أحد العصر إلا في
-- بني قريظة» عن ابن عمر (البخاري 946 — لفظ البخاري تحديدًا؛ رواية
-- مسلم بلفظ "الظهر" فلم تُنسب له).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الخمسة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) المفهوم والتاريخ
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1f2ec282-4db6-475c-8406-8f08fc7f837c' AND title='مفهوم مقاصد الشريعة ونشأة علم المقاصد') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مفهوم مقاصد الشريعة ونشأة علم المقاصد', 'تعريف مقاصد الشريعة وبيان أطوار نشأة علمها من التطبيق الضمني إلى التقعيد المستقل عند الشاطبي وابن عاشور', '1f2ec282-4db6-475c-8406-8f08fc7f837c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'تعريف مقاصد الشريعة وأطوار نشأة علمها', 'مقاصد الشريعة هي الحكم والغايات التي شرعت الأحكام لتحقيقها، جلبًا للمصالح ودرءًا للمفاسد عن العباد في الدنيا والآخرة. وقد مرّ العلم بها بأطوار: تطبيق ضمني عند الصحابة والتابعين في اجتهادهم دون تنظير، ثم أول من نبّه عليها صراحة كالحكيم الترمذي وإمام الحرمين الجويني في "البرهان"، ثم نظّمها الغزالي في "المستصفى" ضمن مباحث أصول الفقه، حتى بلغت أوج نضجها المنهجي عند الشاطبي في "الموافقات" الذي أفرد لها قسمًا مستقلاً سمّاه "كتاب المقاصد"، وانتهاءً باستقلالها علمًا قائمًا بذاته على يد محمد الطاهر بن عاشور في كتابه "مقاصد الشريعة الإسلامية" الذي دعا فيه صراحة إلى إفرادها عن أصول الفقه علمًا مستقلاً.', 1),
    (v_lesson, 'examples', 'الرحمة أصل جامع لمقاصد الشريعة', 'قال تعالى: ﴿وَمَا أَرْسَلْنَاكَ إِلَّا رَحْمَةً لِّلْعَالَمِينَ﴾ (الأنبياء: 107)، قررت أن الرحمة هي الغاية الجامعة لبعثة النبي صلى الله عليه وسلم. وقد جعل ابن عاشور من هذه الرحمة العامة أصلًا تتفرع عنه سائر مقاصد الشريعة الجزئية في العبادات والمعاملات، وبنى عليها تصوره لعلم المقاصد بوصفه كشفًا عن حكمة الشارع في تشريعاته لا تقييدًا لها أو تعطيلًا لنصوصها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مقاصد الشريعة الإسلامية — محمد الطاهر بن عاشور', 1);
  END IF;

  -- 2) الكليات الخمس
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='95e111a0-1c3c-473c-b365-a558dd66abe1' AND title='الكليات الخمس: الضروريات التي جاءت الشريعة بحفظها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الكليات الخمس: الضروريات التي جاءت الشريعة بحفظها', 'بيان الكليات الخمس عند الشاطبي: حفظ الدين والنفس والعقل والنسل والمال، وردّ الأحكام الشرعية إليها', '95e111a0-1c3c-473c-b365-a558dd66abe1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الكليات الخمس عند الشاطبي', 'قرر الشاطبي في "الموافقات" أن الشريعة جاءت بحفظ خمس كليات هي: حفظ الدين، وحفظ النفس، وحفظ العقل، وحفظ النسل، وحفظ المال، وأنها الأصول التي اتفقت الشرائع السماوية كلها على رعايتها. وكل حكم شرعي في العبادات أو المعاملات أو الحدود يمكن ردّه إلى حفظ واحدة منها أو أكثر، إما من جهة الوجود بإقامة ما يحفظها، أو من جهة العدم بدرء ما يهدمها. والشاطبي هو أول من صاغ هذه الكليات بهذه الصورة الخماسية المنضبطة التي صارت مرجع كل من كتب في المقاصد بعده.', 1),
    (v_lesson, 'examples', 'حفظ النفس والمال والعرض في القرآن والسنة', 'قال تعالى: ﴿وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ﴾ (الإسراء: 33)، أصّلت لحفظ النفس بتحريم القتل إلا بموجب شرعي. وقد جمع النبي صلى الله عليه وسلم بين حفظ النفس والمال والعرض في موضع واحد، فعن أبي بكرة رضي الله عنه أن النبي صلى الله عليه وسلم قال في خطبته يوم النحر بحجة الوداع: «إن دماءكم وأموالكم وأعراضكم عليكم حرام كحرمة يومكم هذا» (متفق عليه، رواه البخاري 67 ومسلم 1679)، فنص في عبارة واحدة جامعة على ثلاث من الكليات الخمس.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الموافقات — أبو إسحاق الشاطبي', 1);
  END IF;

  -- 3) مراتب المصالح
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='0c0dc7f3-9fd7-4ed2-92b8-bec22b23ed83' AND title='مراتب المصالح: الضروريات والحاجيات والتحسينيات') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مراتب المصالح: الضروريات والحاجيات والتحسينيات', 'تقسيم الشاطبي للمصالح إلى ضروريات وحاجيات وتحسينيات وبيان العلاقة بينها', '0c0dc7f3-9fd7-4ed2-92b8-bec22b23ed83', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'المراتب الثلاث للمصالح عند الشاطبي', 'قسّم الشاطبي المصالح التي تحفظ بها الكليات الخمس إلى ثلاث مراتب متدرجة: الضروريات، وهي ما لا تقوم الحياة الدينية والدنيوية إلا بها، بحيث يؤدي فواتها إلى فساد عام واختلال؛ والحاجيات، وهي ما يُحتاج إليه للتوسعة ورفع الحرج والمشقة عن المكلفين دون أن يبلغ فواتها حد الفساد العام؛ والتحسينيات، وهي ما يرجع إلى محاسن العادات ومكارم الأخلاق وتحسين أحوال المكلفين. وقرر الشاطبي أن هذه المراتب مرتبطة يخدم بعضها بعضًا، فحفظ الحاجيات والتحسينيات يعود في الجملة إلى حفظ الضروريات وتكميلها وتحسينها.', 1),
    (v_lesson, 'examples', 'رخصة الفطر ويسر الدين مثالان على الحاجيات', 'قال تعالى: ﴿وَمَن كَانَ مَرِيضًا أَوْ عَلَىٰ سَفَرٍ فَعِدَّةٌ مِّنْ أَيَّامٍ أُخَرَ ۗ يُرِيدُ اللَّهُ بِكُمُ الْيُسْرَ وَلَا يُرِيدُ بِكُمُ الْعُسْرَ﴾ (البقرة: 185)، رخصة الفطر في السفر أو المرض مثال ظاهر على مرتبة الحاجيات التي ترفع المشقة عن المكلف دون أن يكون تركها مفسدًا لأصل الدين. وقد قعّد النبي صلى الله عليه وسلم هذا المعنى قاعدة عامة، فعن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم قال: «إن الدين يسر، ولن يشادّ الدين أحد إلا غلبه، فسدِّدوا وقاربوا وأبشروا» (رواه البخاري 39).', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الموافقات — أبو إسحاق الشاطبي', 1);
  END IF;

  -- 4) المآلات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2411edea-0f0b-4b96-8c2a-b8563e3d02ab' AND title='اعتبار المآلات: النظر في نتائج الأفعال عند الحكم الشرعي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('اعتبار المآلات: النظر في نتائج الأفعال عند الحكم الشرعي', 'بيان قاعدة اعتبار المآل عند الشاطبي بمثال النبي صلى الله عليه وسلم في عدم نقض الكعبة', '2411edea-0f0b-4b96-8c2a-b8563e3d02ab', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'قاعدة اعتبار المآل عند الشاطبي', 'اعتبار المآل هو النظر في نتائج الأفعال ومآلاتها قبل الحكم عليها بالإذن أو المنع، فقد يكون الفعل مشروعًا في أصله، لكن فعله في ظرف معين قد يؤدي إلى مفسدة تربو على مصلحته، فيُمتنع منه حينئذ لا لذاته بل لمآله. وقد أفرد الشاطبي لهذه القاعدة فصلاً مستقلاً في "الموافقات" ضمن كتاب الأدلة الشرعية، وعدّها من أدق أبواب الاجتهاد وأخطرها، لأنها تجعل النظر في المصلحة نظرًا مآليًا لا آنيًا فحسب.', 1),
    (v_lesson, 'examples', 'النبي صلى الله عليه وسلم يترك الأفضل مراعاة للمآل', 'عن عائشة رضي الله عنها أن النبي صلى الله عليه وسلم قال: «لولا حداثة عهد قومك بالكفر لنقضت الكعبة ولجعلتها على أساس إبراهيم، فإن قريشًا حين بنت البيت استقصرت» (متفق عليه، رواه البخاري 1585 ومسلم 1333). امتنع النبي صلى الله عليه وسلم عن إعادة بناء الكعبة على قواعد إبراهيم عليه السلام مع كونه الأصل الأكمل، مراعاةً لمآل هذا الفعل في نفوس قوم حديثي عهد بالإسلام قد يفتنهم تغيير بيت طالما عرفوه، فقدّم درء مفسدة الفتنة المحتملة على تحصيل تلك المصلحة الأصلية، وهو المثال الذي يستشهد به عادة على اعتبار المآل عند تزاحم المصالح.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الموافقات — أبو إسحاق الشاطبي', 1);
  END IF;

  -- 5) التطبيقات وضوابط الاستدلال
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='03df5f79-9f55-4660-a207-24beea94db5e' AND title='ضوابط الاستدلال بالمقاصد وتطبيقاتها في الاجتهاد') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('ضوابط الاستدلال بالمقاصد وتطبيقاتها في الاجتهاد', 'أهم ضوابط الاستدلال بمقاصد الشريعة عند القرضاوي بمثال حديث بني قريظة في التوازن بين ظاهر النص ومقصده', '03df5f79-9f55-4660-a207-24beea94db5e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'ضوابط الاستدلال بمقاصد الشريعة', 'من أهم الضوابط التي قررها العلماء لصحة الاستدلال بمقاصد الشريعة: ألا تتعارض مع نص قطعي الثبوت والدلالة فيُقدَّم النص عليها، وأن تُستعمل عونًا على فهم النصوص الجزئية لا بديلاً عنها أو معطلاً لها، وأن يُراعى التوازن بين ظاهر اللفظ ومقصده عند تزاحمهما. وقد أفرد يوسف القرضاوي في كتابه "دراسة في فقه مقاصد الشريعة: بين المقاصد الكلية والنصوص الجزئية" فصلاً مستقلاً في هذه الضوابط، مبينًا كيفية التوفيق بين النظر المقصدي والنظر النصي عند الاجتهاد في النوازل المعاصرة.', 1),
    (v_lesson, 'examples', 'حديث بني قريظة: التوازن بين ظاهر النص ومقصده', 'عن ابن عمر رضي الله عنهما قال: قال النبي صلى الله عليه وسلم لنا لما رجع من الأحزاب: «لا يصلين أحد العصر إلا في بني قريظة»، فأدرك بعضهم العصر في الطريق، فقال بعضهم: لا نصلي حتى نأتيها، وقال بعضهم: بل نصلي، لم يُرد منا ذلك، فذُكر ذلك للنبي صلى الله عليه وسلم فلم يعنِّف واحدًا منهم (رواه البخاري 946). أخذ الفريق الأول بظاهر لفظ الأمر فأخّر الصلاة حتى الوصول، وأخذ الفريق الثاني بمقصده وهو الحث على الإسراع فصلى في الطريق، وأقرّهما النبي صلى الله عليه وسلم معًا، فصار هذا الحديث أصلًا يُستدل به في ضوابط التوازن بين ظاهر النص ومقصده عند الاجتهاد.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'دراسة في فقه مقاصد الشريعة: بين المقاصد الكلية والنصوص الجزئية — يوسف القرضاوي', 1);
  END IF;

  UPDATE categories SET status='published', updated_at=now()
  WHERE slug IN ('mafhum-maqasid','kulliyat-khams','maratib-masalih','maalat','tatbiqat-istidlal')
  AND status='draft';
END $$;
